// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  // Helper to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('cloud')) return '☁️';
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('fog')) return '🌫️';
    return '🌤️'; // default
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="center">
        {/* Header with city name */}
        <Stack gap="var(--ggui-spacing-2)" align="center">
          <Heading level={1} align="center" color="var(--ggui-color-onSurface, #18181b)">
            {props.city}
          </Heading>
        </Stack>

        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" radius="lg" style={{ maxWidth: '500px', width: '100%' }}>
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Current temperature and condition */}
            {/* Current temperature and condition */}
            <Stack gap="var(--ggui-spacing-4)" align="center">
              <Icon name={getWeatherEmoji(props.condition)} size={64} />
              <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">
                {props.temperature}°{props.unit}
              </Heading>
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.condition}
              </Text>
            </Stack>

            <Divider margin="var(--ggui-spacing-4)" />

            {/* Weather details */}
            <Stack gap="var(--ggui-spacing-4)" direction="horizontal" justify="around" align="center" style={{ width: '100%' }}>
              {/* Humidity */}
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                  {props.humidity}%
                </Text>
              </Stack>

              {/* Wind Speed */}
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-day forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%', maxWidth: '500px' }}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="semibold">
              5-Day Forecast
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap style={{ width: '100%' }}>
              {props.forecast.map((day, index) => (
                <Card key={index} shadow="sm" padding="var(--ggui-spacing-3)" radius="md" style={{ flex: 1, minWidth: '80px', textAlign: 'center' }}>
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    {/* Day name */}
                    {day.day && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                        {day.day}
                      </Text>
                    )}
                    {/* Weather icon/emoji */}
                    {day.icon && (
                      <Icon name={day.icon} size={32} />
                    )}
                    {/* High/Low temperatures */}
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      {day.high !== undefined && (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                          {day.high}°{props.unit}
                        </Text>
                      )}
                      {day.low !== undefined && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {day.low}°{props.unit}
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Card>
              ))}  
            </Stack>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

