import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const submit = useAction<ActionSubmitPayload>('submit');

  // Form state
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  const isStep1Valid = name.trim() !== '' && isValidEmail(email);
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true; // Features step is optional
  const isStep4Valid = true; // Comments step is optional

  const canProceed = 
    currentStep === 1 ? isStep1Valid : 
    currentStep === 2 ? isStep2Valid : 
    currentStep === 3 ? isStep3Valid : 
    currentStep === 4 ? isStep4Valid : 
    false;

  const handleNext = () => {
    if (currentStep < 5) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleSubmit = () => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  };

  // Radio options for satisfaction
  const satisfactionOptions = props.satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label,
  }));

  // Checkbox options for features
  const featureCheckboxes = props.featureOptions.map(feature => ({
    label: feature,
    checked: features.includes(feature),
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Progress bar */}
        <div>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 4
          </Text>
          <Progress
            value={currentStep}
            max={4}
            variant="default"
            size="md"
            style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
          />
        </div>

        {/* Step 1: Name & Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={name}
                onChange={setName}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={setEmail}
                error={email && !isValidEmail(email) ? 'Invalid email format' : ''}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => {
                      if (checked) {
                        setFeatures([...features, feature]);
                      } else {
                        setFeatures(features.filter(f => f !== feature));
                      }
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback (optional)"
                value={comments}
                onChange={(value) => setComments(value.slice(0, 500))}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text>{name}</Text>
                </div>
                <Divider margin="var(--ggui-spacing-2)" />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text>{email}</Text>
                </div>
                <Divider margin="var(--ggui-spacing-2)" />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                  <Text>{props.satisfactionLabels[Math.max(0, Math.min(parseInt(satisfaction, 10) - 1, props.satisfactionLabels.length - 1))] || 'N/A'}</Text>
                </div>
                <Divider margin="var(--ggui-spacing-2)" />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features of Interest</Text>
                  <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                    {features.length > 0 ? features.map(f => <Text key={f}>• {f}</Text>) : <Text variant="caption">None selected</Text>}
                  </Stack>
                </div>
                <Divider margin="var(--ggui-spacing-2)" />
                <div>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments (max 500 characters)</Text>
                  <Text>{comments || '(No comments)'}</Text>
                </div>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="end">
          {currentStep > 1 && (
            <Button variant="outline" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 5 && (
            <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; priority?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state for tasks (merges props.tasks + stream updates)
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [showAddForm, setShowAddForm] = useState<string | null>(null); // Which column is adding a task
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Update local tasks when props change
  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen for real-time task updates from other users
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setLocalTasks((prev) => {
        const exists = prev.find((t) => t.id === updatedTask.id);
        if (!exists) {
          // New task from another user
          return [...prev, updatedTask];
        } else {
          // Update existing task
          return prev.map((t) => (t.id === updatedTask.id ? updatedTask : t));
        }
      });
    }
  }, [taskChanged.latest]);

  // Helper: move a task to a new column
  const moveTask = (taskId: string, newColumnId: string) => {
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: newColumnId } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumnId } });
  };

  // Helper: create a new task
  const createTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const taskId = `task-${Date.now()}-${Math.random()}`;
    const newTask = {
      id: taskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '',
      column: columnId,
      dueDate: '',
    };
    setLocalTasks((prev) => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId,
      data: { column: columnId, title: newTaskTitle, priority: newTaskPriority },
    });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setShowAddForm(null);
  };

  // Helper: edit a task title
  const editTask = (taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    taskUpdate({
      action: 'edit',
      taskId,
      data: { column: localTasks.find((t) => t.id === taskId)?.column || '', title: newTitle },
    });
    setEditingTaskId(null);
  };

  // Get tasks for each column
  const getTasksByColumn = (columnId: string) => {
    return localTasks.filter((t) => t.column === columnId);
  };

  // Calculate summary stats
  const totalTasks = localTasks.length;
  const completedTasks = getTasksByColumn(props.columns?.find((c) => c.id === 'done')?.id || 'done').length;

  // Priority badge colors
  const getPriorityVariant = (priority: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  // TaskCard sub-component
  // TaskCard sub-component
  const TaskCard = ({ task, columnId }: { task: typeof localTasks[0]; columnId: string }) => {
    const isEditing = editingTaskId === task.id;

    return (
      <Card
        padding="var(--ggui-spacing-4)"
        shadow="sm"
        radius="md"
        key={task.id}
      >
        <Stack gap="var(--ggui-spacing-2)" align="stretch">
          {isEditing ? (
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Input
                label="Edit task"
                value={editingTitle}
                onChange={setEditingTitle}
                placeholder="Task title"
              />
              <Button
                variant="primary"
                size="sm"
                onClick={() => editTask(task.id || '', editingTitle)}
              >
                Save
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setEditingTaskId(null)}
              >
                Cancel
              </Button>
            </Stack>
          ) : (
            <Stack gap="var(--ggui-spacing-2)" align="stretch">
              <Text variant="label" weight="semibold">
                {task.title || 'Untitled'}
              </Text>
              <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center" justify="between">
                <Badge variant={getPriorityVariant(task.priority || 'medium')} size="sm">
                  {task.priority || 'medium'}
                </Badge>
                {task.assignee && (
                  <Avatar name={task.assignee} size="sm" shape="circle" />
                )}
              </Stack>
              {task.dueDate && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Due: {task.dueDate}
                </Text>
              )}
              <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                <Dropdown
                  trigger={<Button variant="ghost" size="sm">Move</Button>}
                  options={props.columns
                    ?.filter((col) => col.id !== columnId)
                    ?.map((col) => ({
                      value: col.id || '',
                      label: col.name || 'Unknown',
                    })) || []}
                  value=""
                  onChange={(newColumnId) => moveTask(task.id || '', newColumnId)}
                  placement="bottom-start"
                />
              </Row>
              <Button
                variant="ghost"
                size="xs"
                fullWidth
                onClick={() => setEditingTaskId(task.id || '')}
              >
                Edit
              </Button>
            </Stack>
          )}
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
            <Text variant="label">
              Total Tasks: <span style={{ fontWeight: 'bold' }}>{totalTasks}</span>
            </Text>
            <Text variant="label">
              Completed: <span style={{ fontWeight: 'bold' }}>{completedTasks}</span> /{' '} {totalTasks}
            </Text>
            {totalTasks > 0 && (
              <Progress
                value={completedTasks}
                max={totalTasks}
                variant="success"
                size="md"
                showLabel={false}
              />
            )}
          </Row>
        </Card>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" justify="start" wrap>
          {props.columns?.map((column) => {
            const columnTasks = getTasksByColumn(column.id || '');
            return (
              <Box
                key={column.id}
                paddingY="var(--ggui-spacing-4)"
                paddingX="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                style={{ minWidth: '300px', maxWidth: '350px', flex: '0 1 auto' }}
              >
                <Stack gap="var(--ggui-spacing-4)" align="stretch">
                  {/* Column Header */}
                  <Stack gap="var(--ggui-spacing-2)" direction="horizontal" justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Stack>

                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                  {/* Task List */}
                  <Stack gap="var(--ggui-spacing-3)" align="stretch">
                    {columnTasks.map((task) => (
                      <TaskCard key={task.id} task={task} columnId={column.id || ''} />
                    ))}
                  </Stack>

                  {/* Add Task Form / Button */}
                  {showAddForm === column.id ? (
                    <Stack gap="var(--ggui-spacing-2)" align="stretch">
                      <Input
                        label="Task title"
                        value={newTaskTitle}
                        onChange={setNewTaskTitle}
                        placeholder="Enter task title"
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Row gap="var(--ggui-spacing-2)" justify="end">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setShowAddForm(null)}
                        >
                          Cancel
                        </Button>
                        <Button
                          variant="primary"
                          size="sm"
                          onClick={() => createTask(column.id || '')}
                        >
                          Add
                        </Button>
                      </Row>
                    </Stack>
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      fullWidth
                      onClick={() => setShowAddForm(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

