  const getCategoryBorderColor = useCallback((category?: string) => {
    if (!category) return 'var(--ggui-color-outline, #d4d4d8)';
    const colorMap: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'alkaline earth metal': 'var(--ggui-color-success-500, #22c55e)',
      'transition metal': 'var(--ggui-color-warning-500, #f59e0b)',
