        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          onSearch={() => {}}
          placeholder="Search by name or symbol..."
          size="md"
        />
      </Stack>

      {/* Legend */}
      <Card padding="var(--ggui-spacing-4)" radius="md" shadow="sm">
        <Stack gap="var(--ggui-spacing-4)">
