               No elements found matching '{searchQuery}'
             </Text>
           </Stack>
         </Card>
       )}

      {/* Element Detail Panel */}
      {selectedElement && (
        <Card padding="var(--ggui-spacing-6)" radius="lg" shadow="md">
          <Stack gap="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)" direction="horizontal" justify="between" align="start">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
                  <Badge
                    variant="primary"
                    size="md"
                    style={{
                      background: getCategoryColor(selectedElement.category),
                      color: 'var(--ggui-color-onSurface, #18181b)',
                    }}
                  >
                    {selectedElement.category || 'Unknown'}
                  </Badge>
                </Stack>
              </Stack>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                ✕ Close
              </Button>
            </Stack>

            <Divider />

            <Stack gap="var(--ggui-spacing-4)" direction="horizontal" wrap>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Symbol
                </Text>
                <Text variant="bodyLarge" weight="bold">
                  {selectedElement.symbol}
                </Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Number
                </Text>
                <Text variant="bodyLarge" weight="bold">
                  {selectedElement.atomicNumber}
                </Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Weight
                </Text>
                <Text variant="bodyLarge" weight="bold">
                  {selectedElement.atomicWeight ? selectedElement.atomicWeight.toFixed(2) : 'N/A'}
                </Text>
