import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [selectedTab, setSelectedTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  // Safe data extraction with defaults
  const productId = props.product?.id || '';
  const productName = props.product?.name || '';
  const price = props.product?.price || 0;
  const currency = props.product?.currency || '$';
  const rating = Math.min(5, Math.max(0, props.product?.rating || 0));
  const reviewCount = props.product?.reviewCount || 0;
  const stock = props.product?.stock || 0;
  const description = props.product?.description || '';
  const specifications = Array.isArray(props.product?.specifications) ? props.product.specifications : [];
  const reviews = Array.isArray(props.product?.reviews) ? props.product.reviews : [];

  // Derived values
  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;
  const stockStatus = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';
  const stockVariant = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';
  const maxQuantity = Math.max(1, stock);

  // Handlers
  const handleQuantityChange = useCallback((newQuantity: number) => {
    const clamped = Math.max(1, Math.min(newQuantity, maxQuantity));
    setQuantity(clamped);
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && productId) {
      addToCart({ productId, quantity });
    }
  }, [productId, quantity, isOutOfStock, addToCart]);

  // Rating stars helper
  const renderStars = (rate: number) => {
    return (
      <Row gap={2} align="center">
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon
            key={star}
            name={star <= Math.round(rate) ? 'starFilled' : 'star'}
            size={16}
            color={star <= Math.round(rate) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'}
          />
        ))}
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {rate.toFixed(1)} ({reviewCount})
        </Text>
      </Row>
    );
  };

  // Tab items for Tabs component
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack gap={12}>
          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
            {description || 'No description available.'}
          </Text>
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: specifications.length > 0 ? (
        <Table
          columns={[
            { key: 'key', header: 'Property', width: '40%' },
            { key: 'value', header: 'Value', width: '60%' },
          ]}
          data={specifications.map((spec: any, idx: number) => ({
            key: spec?.key || `spec-${idx}`,
            value: spec?.value || '',
          }))}
          compact
        />
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          No specifications available.
        </Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: reviews.length > 0 ? (
        <Stack gap={16}>
          {reviews.map((review: any, idx: number) => (
            <Card key={idx} padding={16} shadow="sm">
              <Stack gap={8}>
                <Row justify="between" align="start">
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {review?.author || 'Anonymous'}
                    </Text>
                    <Row gap={4} align="center">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <Icon
                          key={star}
                          name="star"
                          size={14}
                          color={
                            star <= (review?.rating || 0)
                              ? 'var(--ggui-color-warning-500, #f59e0b)'
                              : 'var(--ggui-color-outlineVariant, #e4e4e7)'
                          }
                        />
                      ))}
                    </Row>
                  </Stack>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {review?.date
                      ? new Date(review.date).toLocaleDateString()
                      : 'N/A'}
                  </Text>
                </Row>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  {review?.text || ''}
                </Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          No reviews yet.
        </Text>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={24}>
        {/* Top section: Product image, title, price, rating, stock */}
        <Stack direction="horizontal" gap={24} align="start" wrap style={{ '@media (max-width: 768px)': { flexDirection: 'column' } }}>
          {/* Product image placeholder */}
          <Box
            background="var(--ggui-color-primary-100, #e0f2fe)"
            padding={24}
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{ minWidth: '300px', height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}
          >
            <Stack gap={12} align="center" justify="center">
              <Icon name="box" size={48} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" align="center">
                {productName}
              </Text>
            </Stack>
          </Box>

          {/* Product details column */}
          <Stack gap={16} style={{ flex: 1, minWidth: '280px' }}>
            {/* Title and rating */}
            <Stack gap={8}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {productName}
              </Heading>
              {renderStars(rating)}
            </Stack>

            {/* Price */}
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{currency}{price.toFixed(2)}</Text>

            {/* Stock status badge */}
            <Badge variant={stockVariant} size="md">
              {stockStatus}
            </Badge>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin={16} />

        {/* Middle section: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={selectedTab}
          onChange={setSelectedTab}
          variant="line"
          size="md"
        />

        <Divider orientation="horizontal" margin={16} />

        {/* Bottom section: Quantity selector and Add to Cart */}
        <Stack gap={16} direction="horizontal" align="center" wrap>
          {/* Quantity selector */}
          <Stack gap={8} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Quantity:
            </Text>
            <Row gap={8} align="center">
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity - 1)}
                disabled={quantity <= 1}
              >
                −
              </Button>
              <Box
                padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                style={{
                  minWidth: '48px',
                  textAlign: 'center',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)" align="center">
                  {quantity}
                </Text>
              </Box>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity + 1)}
                disabled={quantity >= maxQuantity}
              >
                +
              </Button>
            </Row>
          </Stack>

          <Spacer size="flex" />

          {/* Add to Cart button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
            fullWidth={false}
          >
            {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
