// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state
  const [messageInput, setMessageInput] = useState<string>('');
  const [allMessages, setAllMessages] = useState(props.messages);

  // Update messages when props change
  useEffect(() => {
    setAllMessages(props.messages);
  }, [props.messages]);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Listen for new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Listen for typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Handle message send
  const handleSendMessage = useCallback(() => {
    if (messageInput.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageInput, timestamp });
      // Optionally clear input after sending
      setMessageInput('');
    }
  }, [messageInput, sendMessage]);

  // Handle Enter key to send
  // Handle Enter key to send (only for Input, not TextArea)
  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Format timestamp for display
  const formatTime = (ts: string | undefined) => {
    if (!ts) return '';
    try {
      const date = new Date(ts);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const sender = msg.sender || 'Unknown';
      if (groups.length > 0 && groups[groups.length - 1].sender === sender) {
        groups[groups.length - 1].messages.push(msg);
      } else {
        groups.push({ sender, messages: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-6)" border>
        <Stack gap="var(--ggui-spacing-6)" direction="vertical">
          {/* Header */}
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="vertical" gap="var(--ggui-spacing-2)">
              <Heading level={3}>{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">
              {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
            </Badge>
          </Stack>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Message List */}
          <Box
            background="var(--ggui-color-surface, #ffffff)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            padding="var(--ggui-spacing-4)"
            style={{
              maxHeight: '400px',
              overflowY: 'auto',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Stack direction="vertical" gap="var(--ggui-spacing-4)">
              {groupedMessages.length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              ) : (
                groupedMessages.map((group, idx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  const groupKey = `${group.sender}-${idx}`;
                  return (
                    <Stack
                      key={groupKey}
                      direction="vertical"
                      gap="var(--ggui-spacing-2)"
                      align={isCurrentUser ? 'end' : 'start'}
                    >
                      {group.messages.map((msg, msgIdx) => {
                        const msgKey = `${groupKey}-${msgIdx}`;
                        return (
                          <Box
                            key={msgKey}
                            padding="var(--ggui-spacing-3)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                            }
                            borderRadius="var(--ggui-shape-radius-md, 8px)"
                            style={{
                              maxWidth: '75%',
                              wordWrap: 'break-word',
                            }}
                          >
                            <Stack direction="vertical" gap="var(--ggui-spacing-1)">
                              {!isCurrentUser && (
                                <Text
                                  variant="label"
                                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                                  size="xs"
                                >
                                  {group.sender}
                                </Text>
                              )}
                              <Text
                                variant="body"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-50, #f0f9ff)'
                                    : 'var(--ggui-color-onSurface, #18181b)'
                                }
                              >
                                {msg.text}
                              </Text>
                              <Text
                                variant="caption"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                    : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                }
                                size="xs"
                              >
                                {formatTime(msg.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        );
                      })}
                    </Stack>
                  );
                })
              )}

              {/* Typing Indicator */}
              {typingUser && (
                <Stack direction="vertical" gap="var(--ggui-spacing-2)" align="start">
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ fontStyle: 'italic' }}
                  >
                    {typingUser} is typing
                    <span style={{ animation: 'blink 1.4s infinite' }}>...</span>
                  </Text>
                  <style>{`
                    @keyframes blink {
                      0%, 20%, 50%, 80%, 100% { opacity: 1; }
                      40% { opacity: 0.5; }
                      60% { opacity: 0.7; }
                    }
                  `}</style>
                </Stack>
              )}

              {/* Scroll anchor */}
              <div ref={messagesEndRef} />
            </Stack>
          </Box>

          {/* Input Area */}
          <Stack direction="vertical" gap="var(--ggui-spacing-2)">
            <Input
              label="Message"
              value={messageInput}
              onChange={setMessageInput}
              onKeyDown={handleKeyDown}
              placeholder="Type your message..."
              disabled={false}
            />
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" justify="end">
              <Button
                variant="primary"
                size="md"
                onClick={handleSendMessage}
                disabled={!messageInput.trim()}
              >
                Send Message
              </Button>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

