import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: merge initial stocks with price updates
  const [stocks, setStocks] = useState(() => props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Effect: merge price updates into stock list and highlight updated stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updated = priceUpdate.latest;
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === updated.symbol) {
            return {
              ...stock,
              price: updated.price !== undefined ? updated.price : stock.price,
              change: updated.change !== undefined ? updated.change : stock.change,
              changePercent: updated.changePercent !== undefined ? updated.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
      });
      setLastUpdated(new Date());
      if (updated.symbol) {
        setHighlightedSymbols((prev) => new Set(prev).add(updated.symbol));
        const timer = setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(updated.symbol);
            return next;
          });
        }, 1000);
        return () => clearTimeout(timer);
      }
    }
  }, [priceUpdate.latest]);

  // Determine if market is open
  const marketIsOpen = marketStatus.latest?.status === 'open';

  // Format last updated timestamp
  const lastUpdatedText = useMemo(() => {
    return lastUpdated.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  }, [lastUpdated]);

  return (
    <>
      <style>{`
        @keyframes ggui-highlight {
          0% { box-shadow: 0 0 0 3px var(--ggui-color-primary-300, #7dd3fc); }
          100% { box-shadow: 0 0 0 0 transparent; }
        }
      `}</style>
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" direction="vertical">
        {/* Header with title and last updated timestamp */}
        <Box>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdatedText}
              </Text>
              <Badge variant="default" size="sm">
                {marketIsOpen ? '🟢 Open' : '🔴 Closed'}
              </Badge>
            </Stack>
          </Stack>
        </Box>

        {/* Stock cards grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-6)',
          }}
        >
          {stocks.length > 0 ? (
            stocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) >= 0;
              const isHighlighted = highlightedSymbols.has(stock.symbol ?? '');
              const changeColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const borderColor = isPositive
                ? 'var(--ggui-color-success-200, #bbf7d0)'
                : 'var(--ggui-color-error-200, #fecaca)';

              return (
                <Card
                  key={stock.symbol}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  radius="lg"
                  border
                  style={{
                    borderColor,
                    borderWidth: '2px',
                    borderColor,
                    borderWidth: '2px',
                    backgroundColor: isHighlighted ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface)',
                    animation: isHighlighted ? 'ggui-highlight 600ms ease-out' : 'none',
                    transition: 'all 200ms ease-in-out',
                >
                  <Stack gap="var(--ggui-spacing-4)" direction="vertical">
                    {/* Ticker symbol */}
                    <Text
                      variant="label"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface)"
                    >
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company name */}
                    {stock.name && (
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant)"
                      >
                        {stock.name}
                      </Text>
                    )}

                    {/* Current price */}
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface)"
                      >
                        ${typeof stock.price === 'number' ? stock.price.toFixed(2) : 'N/A'}
                      </Text>
                    </Stack>

                    {/* Change amount and percentage with arrow */}
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Icon
                        name={isPositive ? 'arrow-up' : 'arrow-down'}
                        size={16}
                        color={changeColor}
                      />
                      <Text variant="body" color={changeColor} weight="semibold">
                        {stock.change !== undefined ? (
                          isPositive ? '+' : ''
                        ) : (null)}{typeof stock.change === 'number' ? stock.change.toFixed(2) : 'N/A'}
                      </Text>
                      <Text variant="body" color={changeColor} weight="semibold">
                        ({stock.changePercent !== undefined ? (
                          isPositive ? '+' : ''
                        ) : (null)}{typeof stock.changePercent === 'number' ? stock.changePercent.toFixed(2) : 'N/A'}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
              <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="center" justify="center">
                <Icon name="trending-up" size={32} color="var(--ggui-color-onSurfaceVariant)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  No stocks to display
                </Text>
              </Stack>
            </Card>
          )}
        </Box>
      </Stack>
    </Container>
    </>
  );

