interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [selectedAvatar, setSelectedAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email);
  const isStep1Valid = name.trim() !== '' && isEmailValid && selectedAvatar;
  const isStep2Valid = role !== '';

  const handleNext = useCallback(() => {
    if (currentStep === 1 && isStep1Valid) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid) {
      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    if (isStep1Valid && isStep2Valid) {
      complete({
        name: name.trim(),
        email: email.trim(),
        avatar: selectedAvatar,
        role,
        emailNotifications,
        theme
      });
    }
  }, [name, email, selectedAvatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid, complete]);

  const progressPercent = ((currentStep - 1) / 2) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Header with step indicator and progress bar */}
        <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%', maxWidth: '600px' }}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Profile Setup</Heading>
            <Badge variant="primary" size="md">Step {currentStep} of 3</Badge>
          </Stack>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Profile Information</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Let's get your basic information set up.
                </Text>
              </Stack>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={name}
                onChange={setName}
                required
                error={name === '' ? 'Name is required' : ''}
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={email}
                onChange={setEmail}
                required
                error={email === '' ? 'Email is required' : !isEmailValid && email !== '' ? 'Please enter a valid email address' : ''}
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Choose Avatar <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
                  {props.avatarOptions.map((avatar) => (
                    <Box
                      key={avatar}
                      as={Clickable}
                      onClick={() => setSelectedAvatar(avatar)}
                      style={{
                        width: '64px',
                        height: '64px',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        border: selectedAvatar === avatar ? '3px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '32px',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                        background: selectedAvatar === avatar ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent'
                      }}>
                      {avatar}
                    </Box>
                  ))}
                </Stack>
              </Stack>

              {/* Step 1 Navigation */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="end">
                <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>
                  Back
                </Button>
                <Button variant="primary" onClick={handleNext} disabled={!isStep1Valid}>
                  Next
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Your Preferences</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Customize your experience.
                </Text>
              </Stack>

              {/* Role Selection */}
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                placeholder="Select your role"
                required
                error={role === '' ? 'Please select a role' : ''}
              />

              {/* Email Notifications Toggle */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Email Notifications
                </Text>
                <Toggle
                  label="Send me email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
              </Stack>

              {/* Theme Preference */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Theme Preference
                </Text>
                <Toggle
                  label="Use dark theme"
                  checked={theme === 'dark'}
                  onChange={(isDark) => setTheme(isDark ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>

              {/* Step 2 Navigation */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="end">
                <Button variant="ghost" onClick={handleBack}>
                  Back
                </Button>
                <Button variant="primary" onClick={handleNext} disabled={!isStep2Valid}>
                  Review
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review Your Information</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your profile details before completing setup.
                </Text>
              </Stack>

              {/* Summary Cards */}
              <Stack gap="var(--ggui-spacing-4)">
                {/* Profile Info Section */}
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Profile Information
                    </Text>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Avatar
                        </Text>
                        <Text variant="body" weight="medium">
                          {selectedAvatar}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Name
                        </Text>
                        <Text variant="body" weight="medium">
                          {name}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email
                        </Text>
                        <Text variant="body" weight="medium">
                          {email}
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>

                {/* Preferences Section */}
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Preferences
                    </Text>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Role
                        </Text>
                        <Text variant="body" weight="medium">
                          {role}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email Notifications
                        </Text>
                        <Badge variant={emailNotifications ? 'success' : 'default'} size="sm">
                          {emailNotifications ? 'Enabled' : 'Disabled'}
                        </Badge>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Theme
                        </Text>
                        <Badge variant="primary" size="sm">
                          {theme === 'dark' ? 'Dark' : 'Light'}
                        </Badge>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>

              {/* Step 3 Navigation */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="end">
                <Button variant="ghost" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
}
